    "whatsnew.v450.propdev.title": "Property Development reborn",
    "whatsnew.v450.propdev.chip": "PropDev",
    "whatsnew.v450.propdev.b1": "Every CRUD action is a click — no more raw forms.",
    "whatsnew.v450.propdev.b2": "16-tab layout in three rows: Master data, Sales lifecycle, Operations.",
    "whatsnew.v450.propdev.b3": "New: Phases, Blocks, Brokers, Price Matrix, Escrow, Snags, plus Validation Rules and Document Templates.",
    "whatsnew.v450.geo.title": "Geo Hub with live HUD",
    "whatsnew.v450.geo.chip": "Geo Hub",
    "whatsnew.v450.geo.b1": "Cursor latitude, longitude and altitude shown live on the globe.",
    "whatsnew.v450.geo.b2": "HSE incidents, punch-list items and diary photos pinned to the 3D map.",
    "whatsnew.v450.geo.b3": "\"View on map\" deeplinks from BIM Hub and Property Development.",
    "whatsnew.v450.bim.title": "BIM 3D viewer upgrades",
    "whatsnew.v450.bim.chip": "BIM-fremviser",
    "whatsnew.v450.bim.b1": "Walk mode works — pointer-lock with WASD, E/Q and Shift to sprint.",
    "whatsnew.v450.bim.b2": "Section Box and Measure tools now have clear on-screen hints.",
    "whatsnew.v450.bim.b3": "Toolbar relocated next to the ViewCube; Models panel collapses cleanly.",
    "whatsnew.v450.housetypes.title": "House Type Catalogue",
